async function renderizarGrafico(graficoId) {
  const response = await fetch(`http://localhost:5004/api/dashboard/graficos/${graficoId}/dados`);
  const result = await response.json();

  if (result.success) {
    const chartData = result.data;
    const ctx = document.getElementById('myChart').getContext('2d');

    new Chart(ctx, {
      type: chartData.tipo_grafico,
      data: {
        labels: chartData.labels,
        datasets: chartData.datasets.map((dataset, index) => ({
          label: dataset.label,
          data: dataset.data,
          backgroundColor: chartData.configuracoes?.colors?.[index] || 'rgba(75, 192, 192, 0.2)',
          borderColor: chartData.configuracoes?.colors?.[index] || 'rgba(75, 192, 192, 1)',
          borderWidth: chartData.configuracoes?.borderWidth || 1
        }))
      },
      options: {
        responsive: true,
        plugins: {
          title: {
            display: true,
            text: chartData.titulo
          },
          subtitle: {
            display: true,
            text: chartData.descricao
          }
        }
      }
    });
  }
}

