document.getElementById('form-criar-grafico').addEventListener('submit', async (e) => {
  e.preventDefault();
  const formData = new FormData(e.target);
  const assuntosSelecionados = Array.from(document.querySelectorAll('input[name="assuntos"]:checked')).map(cb => cb.value);

  const body = {
    titulo: formData.get('titulo'),
    descricao: formData.get('descricao'),
    tipo_grafico: formData.get('tipo_grafico'),
    assuntos: assuntosSelecionados
  };

  const response = await fetch('http://localhost:5004/api/dashboard/graficos', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body)
  });

  const result = await response.json();
  if (result.success) {
    alert('Gráfico criado com sucesso!');
    window.location.href = `/graficos?id=${result.data.id}`;
  }
});
